function jp(array : string[][]) : void {
  for (let i : number = 0; i < array.length; i = i + 2) {
    for (let j : number = 0; j < array[i].length; j++) {
      let t : string = array[i][j]
      array[i][j] = array[(i+1) % array.length][j]
      array[(i+1) % array.length][j] = t
    }
  }
}
